104: function createOwnerDirectory(owner) {
105:   if (owner.includes('@') && owner.includes('/')) {
106:     // Example: @grafana/dataviz-squad
107:     const [org, team] = owner.substring(1).split('/');
108:     return `teams/${org}/${team}`;
109:   } else if (owner.startsWith('@')) {
110:     // Example: @jesdavpet
111:     return `users/${owner.substring(1)}`;
112:   } else {
113:     // Example: user@domain.tld
114:     const [user, domain] = owner.split('@');
115:     return `emails/${user}-at-${domain}`;
116:   }
117: }
