18: /**
19:  * Generate complete codeowners manifest including raw audit, metadata, and processed files
20:  * @param {string} codeownersFilePath - Path to CODEOWNERS file
21:  * @param {string} manifestDir - Directory for manifest files
22:  * @param {string} rawAuditPath - Path for raw audit JSONL file
23:  * @param {string} codeownersJsonPath - Path for teams.json
24:  * @param {string} codeownersByFilenamePath - Path for teams-by-filename.json
25:  * @param {string} filenamesByCodeownerPath - Path for filenames-by-team.json
26:  * @param {string} metadataPath - Path for metadata.json
27:  */
28: async function generateCodeownersManifestComplete(
29:   codeownersFilePath,
30:   manifestDir,
31:   rawAuditPath,
32:   codeownersJsonPath,
33:   codeownersByFilenamePath,
34:   filenamesByCodeownerPath,
35:   metadataPath
36: ) {
37:   try {
38:     await access(manifestDir);
39:   } catch (error) {
40:     await mkdir(manifestDir, { recursive: true });
41:   }
42: 
43:   const newMetadata = generateCodeownersMetadata(codeownersFilePath, manifestDir, 'metadata.json');
44: 
45:   let isCacheUpToDate = false;
46:   try {
47:     const existingMetadata = JSON.parse(await readFile(metadataPath, 'utf8'));
48:     if (
49:       existingMetadata.filesHash === newMetadata.filesHash &&
50:       existingMetadata.codeownersHash === newMetadata.codeownersHash
51:     ) {
52:       isCacheUpToDate = true;
53:     }
54:   } catch (error) {
55:     isCacheUpToDate = false;
56:   }
57: 
58:   if (!isCacheUpToDate) {
59:     await generateCodeownersRawAudit(codeownersFilePath, rawAuditPath);
60:     await generateCodeownersManifest(
61:       rawAuditPath,
62:       codeownersJsonPath,
63:       codeownersByFilenamePath,
64:       filenamesByCodeownerPath
65:     );
66:     await writeFile(metadataPath, JSON.stringify(newMetadata, null, 2), 'utf8');
