3: const fs = require('node:fs');
4: const { stat, writeFile } = require('node:fs/promises');
5: const readline = require('node:readline');
6: 
7: const {
8:   RAW_AUDIT_JSONL_PATH,
9:   CODEOWNERS_BY_FILENAME_JSON_PATH,
10:   FILENAMES_BY_CODEOWNER_JSON_PATH,
11:   CODEOWNERS_JSON_PATH,
12: } = require('./constants.js');
13: 
14: /**
15:  * Generate codeowners manifest files from raw audit data
16:  * @param {string} rawAuditPath - Path to the raw audit JSONL file
17:  * @param {string} codeownersJsonPath - Path to write teams.json
18:  * @param {string} codeownersByFilenamePath - Path to write teams-by-filename.json
19:  * @param {string} filenamesByCodeownerPath - Path to write filenames-by-team.json
20:  */
21: async function generateCodeownersManifest(
22:   rawAuditPath,
23:   codeownersJsonPath,
24:   codeownersByFilenamePath,
25:   filenamesByCodeownerPath
26: ) {
27:   const hasRawAuditJsonl = await stat(rawAuditPath);
28:   if (!hasRawAuditJsonl) {
29:     throw new Error(
30:       `No raw CODEOWNERS audit JSONL file found at: ${rawAuditPath} ... run "yarn codeowners-manifest:raw"`
31:     );
32:   }
33: 
34:   const auditFileInput = fs.createReadStream(rawAuditPath);
35: 
36:   const lineReader = readline.createInterface({
37:     input: auditFileInput,
38:     crlfDelay: Infinity,
39:   });
40: 
41:   let codeowners = new Set();
42:   let codeownersByFilename = new Map();
43:   let filenamesByCodeowner = new Map();
44: 
45:   lineReader.on('error', (error) => {
46:     console.error('Error reading file:', error);
47:     throw error;
48:   });
49: 
50:   lineReader.on('line', (line) => {
51:     try {
52:       const { path, owners: fileOwners } = JSON.parse(line.toString().trim());
53: 
54:       for (let owner of fileOwners) {
55:         codeowners.add(owner);
56:       }
57: 
58:       codeownersByFilename.set(path, fileOwners);
59: 
60:       for (let owner of fileOwners) {
61:         const filenames = filenamesByCodeowner.get(owner) || [];
62:         filenamesByCodeowner.set(owner, filenames.concat(path));
63:       }
64:     } catch (parseError) {
65:       console.error(`Error parsing line: ${line}`, parseError);
66:       throw parseError;
67:     }
68:   });
69: 
70:   await new Promise((resolve) => lineReader.once('close', resolve));
71: 
72:   await Promise.all([
73:     writeFile(codeownersJsonPath, JSON.stringify(Array.from(codeowners).sort(), null, 2)),
74:     writeFile(codeownersByFilenamePath, JSON.stringify(Object.fromEntries(codeownersByFilename), null, 2)),
75:     writeFile(filenamesByCodeownerPath, JSON.stringify(Object.fromEntries(filenamesByCodeowner), null, 2)),
76:   ]);
77: }
78: 
79: if (require.main === module) {
80:   (async () => {
81:     try {
82:       console.log(`📋 Generating files ↔ teams manifests from ${RAW_AUDIT_JSONL_PATH} ...`);
83:       await generateCodeownersManifest(
84:         RAW_AUDIT_JSONL_PATH,
85:         CODEOWNERS_JSON_PATH,
86:         CODEOWNERS_BY_FILENAME_JSON_PATH,
87:         FILENAMES_BY_CODEOWNER_JSON_PATH
88:       );
89:       console.log('✅ Manifest files generated:');
90:       console.log(`   • ${CODEOWNERS_JSON_PATH}`);
91:       console.log(`   • ${CODEOWNERS_BY_FILENAME_JSON_PATH}`);
92:       console.log(`   • ${FILENAMES_BY_CODEOWNER_JSON_PATH}`);
93:     } catch (e) {
94:       console.error(e);
95:       process.exit(1);
96:     }
97:   })();
98: }
99: 
100: module.exports = { generateCodeownersManifest };
